import { Component, Host, Prop, h } from '@stencil/core';

@Component({
  tag: 'mx-title-bar',
  styleUrl: 'mx-title-bar.css',
  shadow: false
})
export class MxTitleBar {
  /** Sets the content of the title. */
  @Prop() readonly titleContent: string;
  /** Sets the link that pressing the back button leads to. */
  @Prop() readonly backButtonLink: string;
  /** Sets whether to display the back button or not. */
  @Prop() readonly showBackButton: boolean;

  render() {
    return (
      <Host>
        <div class='shadow-2'>
          <div class='pb-12 pt-12 flex'>
            <div class='font-medium'>
              {this.showBackButton ? (
                <kds-link size='l' href={this.backButtonLink}>
                  <kds-icon-caret-left></kds-icon-caret-left>Back<span class='pl-12 split'>|</span>
                </kds-link>
              ) : (
                <div></div>
              )}
            </div>
            <div>
              <mx-title-content content={this.titleContent}></mx-title-content>
            </div>
          </div>
        </div>
      </Host>
    );
  }
}
